import { initializeApp } from 'firebase/app';
import { getAuth, Auth } from 'firebase/auth';
import { getFirestore, Firestore } from 'firebase/firestore';
import { getStorage, FirebaseStorage } from 'firebase/storage';

// Firebase configuration
// Replace these with your actual Firebase config from console.firebase.google.com
const firebaseConfig = {
  apiKey: "AIzaSyAeCQ-wgG0OcEj_1JxkgBepBrltFN6Rz4M",
  authDomain: "revise-hub.firebaseapp.com",
  projectId: "revise-hub",
  storageBucket: "revise-hub.firebasestorage.app",
  messagingSenderId: "594941189702",
  appId: "1:594941189702:web:3145dbb48dc08635843447"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);

// Initialize Firebase Authentication and get a reference to the service
export const auth: Auth = getAuth(app);

// Initialize Cloud Firestore and get a reference to the service
export const db: Firestore = getFirestore(app);

// Initialize Cloud Storage and get a reference to the service
export const storage: FirebaseStorage = getStorage(app);

export default app;
